import Name from './Name.js'

const deleteTogglerById = (id) => {
  console.log({id})
}

const Persons = ({filteredPeople}) =>{
return(
  <div>
    <ul>
      {filteredPeople.map(name => <Name key = {name.name} person = {name} deleteTogglerById = {() => deleteTogglerById(name.id)}/>)}
    </ul>
  </div>
)}

export default Persons
